import{_ as s,c as i,o as t,aj as a}from"./chunks/framework.BlveriQe.js";const g=JSON.parse('{"title":"Configuring Primitive Services","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/configuring-primitive-services.md","filePath":"getting-started/configuring-primitive-services.md"}'),n={name:"getting-started/configuring-primitive-services.md"};function o(r,e,l,d,p,h){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="configuring-primitive-services" tabindex="-1">Configuring Primitive Services <a class="header-anchor" href="#configuring-primitive-services" aria-label="Permalink to “Configuring Primitive Services”">​</a></h1><p>Everything Primitive does for your app — which sign-in methods are enabled, what workflows exist, which external APIs can be called, what database operations clients may run — is <strong>configuration of Primitive&#39;s services, stored on the Primitive servers</strong>. Your client code doesn&#39;t define that behavior; it invokes what configuration declares.</p><p>There are two equivalent ways to manage that configuration:</p><ol><li><strong>The <a href="https://admin.primitiveapi.com" target="_blank" rel="noreferrer">Admin Console</a></strong> — interactive and visual. Best for exploring, testing, and one-off changes.</li><li><strong>TOML files in your repo, synced via the CLI</strong> — configuration as code. Best for anything you want versioned, reviewed, reproduced across environments, or managed by an AI coding agent.</li></ol><p>Both edit the same underlying configuration. Most teams explore in the console and commit the result as TOML.</p><h2 id="the-sync-loop" tabindex="-1">The Sync Loop <a class="header-anchor" href="#the-sync-loop" aria-label="Permalink to “The Sync Loop”">​</a></h2><p><code>primitive sync</code> round-trips your app&#39;s configuration between the server and a directory of TOML files:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # create the directory structure</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # download current server config as TOML</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ... edit files locally ...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> diff</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # see what would change</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # apply your changes to the server</span></span></code></pre></div><p>The sync directory auto-resolves to <code>.primitive/sync/&lt;env&gt;/&lt;appId&gt;/</code> — one isolated slot per environment. Pass <code>--dir &lt;path&gt;</code> to override it with a fixed directory.</p><p>The files live in your repo, so configuration changes ride the same workflow as code: branches, diffs, reviews, rollbacks. <code>sync push</code> validates every file before applying anything — a validation error aborts the push with no changes applied — and reports the file and entity behind any failure.</p><p><strong>Preview before you push.</strong> <code>primitive sync diff</code> shows which entities would be created, changed, or removed; <code>primitive sync push --dry-run</code> walks the full push and reports the same outcome without writing anything. One caveat: <code>diff</code> counts entities only, so a change confined to <code>app.toml</code> (app settings) shows up as <code>Local only: 0 / Remote only: 0 / Synced: 0</code> there — preview app-settings changes with <code>push --dry-run</code>, which includes them. Both run the identical validation a real push runs, so a rejection — an operation whose database type has no schema, an unresolved reference, a schema change that would break an existing operation — surfaces in the preview exactly as it would on push. The preview is faithful: what it reports is what <code>sync push</code> will do. And a blocked entity records no sync state, so it stays visible as pending on the next <code>diff</code> instead of quietly reading as &quot;in sync.&quot;</p><p>Every <code>sync pull</code> snapshots the sync directory before writing, so a pull that overwrites local edits is recoverable:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> revert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # list available snapshots</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> revert</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                   # restore the most recent</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> revert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --snapshot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # restore a specific one</span></span></code></pre></div><p>Snapshots are local CLI state, kept out of version control and pruned after 28 days. <code>revert</code> replaces the sync directory with the snapshot — run <code>primitive sync diff</code> afterwards to see where the restored files stand relative to the server.</p><p><strong>Make the sync tree the single source of truth.</strong> Once you manage configuration as TOML, create entities and land changes by editing files and pushing — including throwaway test or debugging workflows — rather than with one-off <code>primitive workflows create</code> calls or console edits. The CLI records each pushed entity&#39;s server identity in <code>.primitive-sync.json</code>, a state file in the sync directory, and uses it to decide whether a push creates or updates each entity; changes made outside the loop leave that state out of date. In particular, an entity <strong>deleted</strong> outside the loop leaves a stale entry behind: the next push of an edited version of its TOML updates an entity that no longer exists and fails with a &quot;not found&quot; error. When a push fails that way, remove that entity&#39;s entry from <code>.primitive-sync.json</code> and push again — the entity is created fresh. And when you retire an entity on purpose, delete it explicitly (CLI or console), then remove its TOML file and its <code>.primitive-sync.json</code> entry together.</p><h2 id="what-lives-in-the-config-directory" tabindex="-1">What Lives in the Config Directory <a class="header-anchor" href="#what-lives-in-the-config-directory" aria-label="Permalink to “What Lives in the Config Directory”">​</a></h2><p>One subdirectory per kind of configuration:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>config/</span></span>
<span class="line"><span>  app.toml                        # App settings</span></span>
<span class="line"><span>  vars.toml                       # Config vars (non-secret key/value store)</span></span>
<span class="line"><span>  workflows/*.toml                # Workflow definitions</span></span>
<span class="line"><span>  workflow-fragments/*.toml       # Reusable step blocks</span></span>
<span class="line"><span>  transforms/*.rhai               # Rhai scripts for workflow script steps</span></span>
<span class="line"><span>  prompts/*.toml                  # Managed prompts</span></span>
<span class="line"><span>  integrations/*.toml             # External API integrations</span></span>
<span class="line"><span>  database-types/*.toml           # Database operations, triggers, subscriptions</span></span>
<span class="line"><span>  webhooks/*.toml                 # Inbound webhooks</span></span>
<span class="line"><span>  cron-triggers/*.toml            # Scheduled workflow triggers</span></span>
<span class="line"><span>  blob-buckets/*.toml             # Blob bucket definitions</span></span>
<span class="line"><span>  email-templates/*.toml          # Email template overrides</span></span>
<span class="line"><span>  rule-sets/*.toml                # Access rule sets</span></span>
<span class="line"><span>  group-type-configs/*.toml       # Group type configuration</span></span>
<span class="line"><span>  collection-type-configs/*.toml  # Collection type configuration</span></span>
<span class="line"><span>  metadata-category-configs/*.toml # Resource metadata category configs</span></span></code></pre></div><p>Every feature page in these docs that shows a TOML block — <a href="./workflows.html">Workflows</a>, <a href="./prompts.html">Prompts</a>, <a href="./api-integrations.html">API Integrations</a>, <a href="./working-with-databases.html">Working with Databases</a>, <a href="./blobs-and-files.html">Blobs and Files</a>, <a href="./resource-metadata.html">Resource Metadata</a> — is describing one of these files. Define the entity in TOML, <code>primitive sync push</code>, and it&#39;s live.</p><p><code>app.toml</code> holds the app-level settings, and pushing it is the preferred way to change them — the imperative <code>primitive apps update --flag</code> calls mutate the server directly and drift from the checked-in TOML, so a later <code>sync push</code> reverts them. The TOML-syncable settings are:</p><ul><li><code>[app]</code> — <code>name</code>, <code>mode</code>, <code>waitlistEnabled</code>, <code>baseUrl</code></li><li><code>[auth]</code> — <code>googleOAuthEnabled</code>, <code>magicLinkEnabled</code>, <code>passkeyEnabled</code>, <code>appleSignInEnabled</code>, <code>appleAudiences</code>, <code>otpEnabled</code>, and <code>[auth.passkeys]</code> relying-party config</li><li><code>[cors]</code> (when <code>mode = &quot;custom&quot;</code>) — <code>allowedOrigins</code>, <code>allowCredentials</code>, <code>allowedMethods</code>, <code>maxAge</code></li></ul><p>Only the keys listed above are pushed — an omitted <code>[auth]</code> key leaves the server value untouched (it isn&#39;t cleared), and an unrecognized <code>[auth]</code> key is ignored with a warning on push. <strong>Redirect URIs</strong> are the one app setting not part of <code>app.toml</code>: set them with <code>primitive apps update --redirect-uris &quot;&lt;uri1&gt;,&lt;uri2&gt;&quot;</code> or in the <a href="https://admin.primitiveapi.com" target="_blank" rel="noreferrer">Admin Console</a>.</p><p><code>vars.toml</code> round-trips your app&#39;s <a href="./app-secrets.html#config-vars">config vars</a> the same way <code>app.toml</code> round-trips app settings — a flat table of non-secret key/value pairs, written by <code>sync pull</code> and applied by <code>sync push</code>.</p><p>Credentials never go in these files: config that needs an API key references it as <span><code>{{secrets.KEY}}</code></span>, with the value stored server-side. See <a href="./app-secrets.html">App Secrets</a>.</p><h2 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to “Environments”">​</a></h2><p>A project usually targets more than one app — a development app for day-to-day coding, a production app for your customers. The CLI&#39;s named environments bind a server and app together so every command (including <code>sync</code>) knows which app it&#39;s talking to, and each environment gets its own isolated sync directory. See <a href="./primitive-cli.html#project-configuration-and-environments">Project Configuration and Environments</a>.</p><h2 id="console-or-code" tabindex="-1">Console or Code? <a class="header-anchor" href="#console-or-code" aria-label="Permalink to “Console or Code?”">​</a></h2><table tabindex="0"><thead><tr><th>Task</th><th>Console</th><th>TOML + CLI</th></tr></thead><tbody><tr><td>Exploring and testing</td><td>Preferred — visual, interactive</td><td>Works but less convenient</td></tr><tr><td>Version-controlled config</td><td>—</td><td>Preferred</td></tr><tr><td>Quick one-off changes</td><td>Convenient</td><td>Convenient</td></tr><tr><td>AI agent automation</td><td>—</td><td>Preferred — agents speak CLI</td></tr><tr><td>CI/CD pipelines</td><td>—</td><td>Preferred — scriptable</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./primitive-cli.html">Primitive CLI</a></strong> — Full CLI reference, environments, and sync details</li><li><strong><a href="./admin-console.html">Admin Console</a></strong> — The interactive view of the same configuration</li><li><strong><a href="./workflows.html">Workflows</a></strong> — The most config-driven feature on the platform</li></ul>`,30)])])}const k=s(n,[["render",o]]);export{g as __pageData,k as default};
